import { useEffect, useState } from "react";
import axios from "axios";
import profile from "../assets/nisha.jpeg";

function Portfolio() {
  const [stats, setStats] = useState({
    visitors: 0,
    projects: 0,
    resume: 0,
    logins: 0,
  });

  useEffect(() => {
    // load analytics stats
    const loadStats = async () => {
      try {
        const res = await axios.get(
          "http://localhost:5000/api/analytics/stats",
        );

        setStats(res.data);
      } catch (err) {
        console.log("analytics error");
      }
    };

    // visitor tracking
    axios.post("http://localhost:5000/api/analytics/visit", {
      page: "portfolio",
      browser: navigator.userAgent,
    });

    loadStats();
  }, []);

  const projectClick = async (name) => {
    try {
      await axios.post("http://localhost:5000/api/analytics/project", {
        project: name,
      });
    } catch (err) {
      console.log("tracking failed");
    }
  };

  const resumeDownload = async () => {
    try {
      await axios.post("http://localhost:5000/api/analytics/resume");
    } catch (err) {
      console.log("tracking failed");
    }
  };

  return (
    <div style={{ display: "flex", padding: "120px", gap: "60px" }}>
      {/* LEFT SIDE */}

      <div style={{ width: "300px" }}>
        <img
          src={profile}
          alt="Nisha"
          style={{
            width: "180px",
            height: "180px",
            borderRadius: "50%",
            objectFit: "cover",
          }}
        />

        <h2>Nisha Yadav</h2>

        <p>
          MERN Stack Developer passionate about building modern web
          applications.
        </p>

        <h3>Analytics</h3>

        <p>Visitors: {stats.visitors}</p>
        <p>Project Clicks: {stats.projects}</p>
        <p>Resume Downloads: {stats.resume}</p>
        <p>Login History: {stats.logins}</p>
      </div>

      {/* RIGHT SIDE */}

      <div>
        <h2>Projects</h2>

        <button onClick={() => projectClick("AI Virtual Mouse")}>
          AI Virtual Mouse
        </button>

        <br />
        <br />

        <button onClick={() => projectClick("AI Wardrobe")}>AI Wardrobe</button>

        <br />
        <br />

        <button onClick={() => projectClick("Travel Booking App")}>
          Travel Booking App
        </button>

        <br />
        <br />

        <a href="/resume.pdf" download onClick={resumeDownload}>
          Download Resume
        </a>
      </div>
    </div>
  );
}

export default Portfolio;
